package com.dell.core.bean;

import java.util.List;

public class Category {
	private String varcategory;
	private List<Question> questions;

	public String getCategory() {
		return varcategory;
	}

	public void setCategory(final String category) {
		this.varcategory = varcategory;
	}

	public List<Question> getQuestions() {
		return questions;
	}

	public void setQuestions(List<Question> questions) {
		this.questions = questions;
	}

	@Override
	public boolean equals(Object categoryObject) {
		if (categoryObject == this) {
			return true;
		}

		if (categoryObject == null || categoryObject.getClass() != this.getClass()) {
			return false;
		}

		Category objcategory = (Category) categoryObject;
		if (this.varcategory.equals(objcategory.getCategory()))
			return true;
		 else
			return false;
	}

	@Override
	public int hashCode() {
		final int prime = 31;
		int result = 1;
		result = prime * result + ((varcategory == null) ? 0 : varcategory.hashCode());
		return result;
	}

}

