package com.dell.core.servlets;

import org.apache.sling.api.servlets.HttpConstants;
import org.apache.sling.api.servlets.ServletResolverConstants;
import org.apache.sling.api.servlets.SlingAllMethodsServlet;
import org.apache.sling.api.SlingHttpServletRequest;
import org.apache.sling.api.SlingHttpServletResponse;
import org.apache.sling.api.resource.LoginException;
import org.apache.sling.api.resource.ResourceResolver;
import org.apache.sling.api.resource.ResourceResolverFactory;
import org.json.simple.JSONArray;
import org.json.simple.JSONObject;
import org.osgi.service.component.annotations.Activate;
import org.osgi.service.component.annotations.Component;
import org.osgi.service.component.annotations.Reference;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.jcr.Node;
import javax.jcr.NodeIterator;
import javax.jcr.RepositoryException;
import javax.jcr.Session;
import javax.jcr.query.Query;
import javax.jcr.query.QueryManager;
import javax.jcr.query.QueryResult;
import javax.servlet.Servlet;
import java.io.IOException;
import java.rmi.ServerException;

@Component(service = {Servlet.class}, property = {
        ServletResolverConstants.SLING_SERVLET_PATHS + "=/eduservice/emc/userandgroup",
        ServletResolverConstants.SLING_SERVLET_METHODS + "=" + HttpConstants.METHOD_GET
})
public class EMCUsersServlet extends SlingAllMethodsServlet {
    private static final Logger LOGGER = LoggerFactory.getLogger(EMCUsersServlet.class);
    private static final long serialVersionUID = -7044612820464341158L;

    @Reference
    private ResourceResolverFactory resolverFactory;

    @Activate
    public void activate() {
        // Activation logic here if needed
    }

    @Override
    protected void doGet(SlingHttpServletRequest request, SlingHttpServletResponse response)
            throws ServerException, IOException {
        try {
            final String jsondata = getUserWithEmail().toJSONString();
            LOGGER.info("User and Group in JSON form : {} ", jsondata);
            response.getWriter().write(jsondata);
        } catch (Exception e) {
            LOGGER.error("Error while calling data : { } ", e);
        }
    }

	@SuppressWarnings("unchecked")
	private JSONObject getUserWithEmail() {
		JSONObject usersandgroups = new JSONObject();
		JSONArray userandgroupArr = new JSONArray();
		ResourceResolver resourceResolver = null;
		try {
			resourceResolver=resolverFactory.getAdministrativeResourceResolver(null);
			final Session session= resourceResolver.adaptTo(Session.class);
			final QueryManager queryManager = session.getWorkspace().getQueryManager();
			final Query query = queryManager.createQuery("SELECT p.* FROM [nt:base] AS p WHERE ISDESCENDANTNODE([/home/users/emc]) or ISDESCENDANTNODE([/home/groups/emc])", Query.JCR_SQL2);
			final QueryResult result = query.execute();
			final NodeIterator nodeIterator = result.getNodes();
			while(nodeIterator.hasNext()){
				final Node node = nodeIterator.nextNode();
				if (node.hasProperty("rep:authorizableId")) {
					String userId = node.getProperty("rep:authorizableId").getString();
					String userName = "";
					JSONObject userandgroup = new JSONObject();
					if(node.hasProperty("jcr:primaryType") && node.getProperty("jcr:primaryType").getValue().toString().equalsIgnoreCase("rep:User")){
						userName = userId + " (User)";
					}else if(node.hasProperty("jcr:primaryType") && node.getProperty("jcr:primaryType").getValue().toString().equalsIgnoreCase("rep:Group")){
						userName = userId + " (Group)";
					}
					userandgroup.put("id", userId);
					userandgroup.put("name", userName);
					userandgroupArr.add(userandgroup);
				}
			}
			usersandgroups.put("data", userandgroupArr);
		} catch (RepositoryException re) {
			LOGGER.error("Error while getting initiator email id {}", re);
		}catch (LoginException e) {
			LOGGER.error("Error while getting resource resolver : { } ", e);
		}finally{
			if(resourceResolver != null){
				resourceResolver.close();
			}
		}
		return usersandgroups;
	}
}

