24	import java.util.stream.Collectors;
25	
26	@Model(
27	        adaptables = SlingHttpServletRequest.class,
28	        defaultInjectionStrategy = DefaultInjectionStrategy.OPTIONAL
29	)
30	public class CourseDetailsModel {
31	
32	    private static final ObjectMapper MAPPER = new ObjectMapper();
33	
34	    @Inject private SlingHttpServletRequest request;
35	    @Inject private XSSAPI xss;
36	
37	
38	    @OSGiService
39	    private CourseApiClient apiClient;
40	
41	    private boolean success;
42	    private CourseInfoResponse apiResponse;
43	    private CoursePayload course;
44	    private String formattedDescriptionHtml;
45	    private String courseInfoJson;
46	
47	    private String blueprintBeforeScheduleHtml;
48	    private String blueprintAfterScheduleHtml;
49	    private String outlineHtml;
50	
51	    private String scheduleTableDataJson = "[]";
52	    private String resolvedModType = "";
53	
54	    public String getUseLocation() {
55	        return useLocation;
56	    }
57	
58	    private String useLocation = "";
59	
60	    private boolean isOtherMod(String modType) {
61	        return "On Demand Class".equals(modType)
62	                || "On Demand Lab".equals(modType)
63	                || "Exam Voucher".equals(modType)
64	                || "Training Credits".equals(modType)
65	                || "Subscription".equals(modType)
66	                || "Assessment".equals(modType);
67	    }
68	
69	    private String resolvedCourseId = "";
70	
71	
72	
73	    @OSGiService
74	    private EndPointsService endPointsService;
75	
76	    private static class ParsedParams {
77	        String courseId;
78	        String mod;
79	    }
80	
81	    private ParsedParams parseCourseAndMod() {
82	        ParsedParams p = new ParsedParams();
83	
84	        String courseIdRaw = request.getParameter("courseID");
85	        String modRaw = request.getParameter("mod");
86	
87	        // Normal path
88	        if (StringUtils.isNotBlank(courseIdRaw) && StringUtils.isNotBlank(modRaw)) {
89	            p.courseId = courseIdRaw.trim();
90	            p.mod = modRaw.trim();
91	            return p;
92	        }
93	
94	        // Broken URL path: courseID contains "&mod=..."
95	        if (StringUtils.isNotBlank(courseIdRaw) && courseIdRaw.contains("&mod=")) {
96	            String[] parts = courseIdRaw.split("&mod=", 2);
97	            p.courseId = parts[0].trim();
98	            p.mod = (parts.length > 1) ? parts[1].trim() : "";
99	            return p;
100	        }
101	
102	        // Another broken variant: "ESCPXS06248?mod=Classroom" (rare but happens)
103	        if (StringUtils.isNotBlank(courseIdRaw) && courseIdRaw.contains("?mod=")) {
104	            String[] parts = courseIdRaw.split("\\?mod=", 2);
105	            p.courseId = parts[0].trim();
106	            p.mod = (parts.length > 1) ? parts[1].trim() : "";
107	            return p;
108	        }
109	
110	        // Fallback
111	        p.courseId = StringUtils.defaultString(courseIdRaw).trim();
112	        p.mod = StringUtils.defaultString(modRaw).trim();
113	        return p;
114	    }
115	
116	    @PostConstruct
117	    protected void init() {
118	        try {
119	            ParsedParams parsed = parseCourseAndMod();
120	            String courseId = parsed.courseId;
121	            String modType  = parsed.mod;
122	
123	            resolvedCourseId = courseId;
124	            resolvedModType = modType;
125	
126	
127	            if (StringUtils.isBlank(courseId) || StringUtils.isBlank(modType)) {
128	                fail();
129	                return;
130	            }
131				
132				EdSvcUserInfo userInfo = request.adaptTo(EdSvcUserInfo.class);
133	
134	                String loc = userInfo != null ? StringUtils.defaultString(userInfo.getLocation()) : getCookieValue(request,"location","United States");
135	                String location = StringUtils.isBlank(loc) ? getCookieValue(request,"location","United States") : loc;
136	
137	
138	            String audType = userInfo != null ? StringUtils.defaultString(userInfo.getTWX_AudienceType()) : "";
139	            String audienceType = StringUtils.isBlank(audType) ? "Customer, ExternalX, " + location : audType;
140	
141	            useLocation = location;
142	            // Build same JSON body as your frontend used
143	            JSONObject payload = new JSONObject();
144	            payload.put("audienceType", audienceType);
145	            payload.put("location", location);
146	            payload.put("country", location);
147	            payload.put("courseId", courseId);
148	            payload.put("deliveryType", modType);
149	
150	            if (endPointsService == null) {
151	                throw new IllegalStateException("EndPointsService not injected into CourseDetailsModel");
152	            }
153	
154	            String absoluteUrl = endPointsService.getStoreApiEndpoint() + "/CashMicroServices/catalog/getOfferingsAndCourseInfo";
155	
156	            apiResponse = apiClient.getOfferingsAndCourseInfo(absoluteUrl, payload);
157	
158	            if (apiResponse == null
159	                    || !"Success".equalsIgnoreCase(apiResponse.message)
160	                    || apiResponse.payload == null
161	                    || apiResponse.payload.isEmpty()) {
162	                fail();
163	                return;
164	            }
165	
166	            course = apiResponse.payload.get(0);
167	            CourseDescriptionFormatter.SplitTabsHtml split =
168	                    CourseDescriptionFormatter.toSplitTabsHtml(course.courseDescription, xss);
169	
170	            blueprintBeforeScheduleHtml = split.tab1BeforeScheduleHtml;
171	            blueprintAfterScheduleHtml  = split.tab1AfterScheduleHtml;
172	            outlineHtml                 = split.tab2OutlineHtml;
173	
174	            resolvedModType = modType; // from parsed params earlier
175	            List<TableRow> rows = buildScheduleTableData(course.offeringsList, resolvedModType, nvl(course.skuModelCode));
176	            scheduleTableDataJson = MAPPER.writeValueAsString(rows);
177	
178	            // Embed full response for JS-only validations/enhancements (NO network)
179	            String json = MAPPER.writeValueAsString(apiResponse);
180	            courseInfoJson = CourseApiClient.safeJsonForScriptTag(json);
181	
182	            success = true;
183	
184	        } catch (Exception e) {
185	            fail();
186	        }
187	    }
188	
189	    private void fail() {
190	        success = false;
191	        apiResponse = null;
192	        course = null;
193	        formattedDescriptionHtml = "";
194	        courseInfoJson = "{}";
195	        blueprintBeforeScheduleHtml = "";
196	        blueprintAfterScheduleHtml = "";
197	        outlineHtml = "";
198	        resolvedModType = "";
199	        scheduleTableDataJson = "[]";
200	        resolvedCourseId = "";
201	
202	    }
203	
204	    private List<TableRow> buildScheduleTableData(List<Offering> offerings, String modType, String skuGlobalCode) {
205	        List<TableRow> data = new ArrayList<>();
206	
207	        if (offerings == null || offerings.isEmpty()) {
208	            return data;
209	        }
210	
211	        // Normalize to avoid NPE/spacing issues
212	        String m = StringUtils.defaultString(modType).trim();
213	
214	        for (Offering o : offerings) {
215	            if (o == null) continue;
216	
217	            String offeringMod = StringUtils.defaultString(o.modalityName).trim();
218	
219	            // seatsAvailable = round(maxCT - studCT) (same as your JS math)
220	            int seatsAvailable = 0;
221	            try {
222	                int max = (o.maxCT != null) ? o.maxCT : 0;
223	                int used = (o.studCT != null) ? o.studCT : 0;
224	                seatsAvailable = Math.round(max - used);
225	                if (seatsAvailable < 0) seatsAvailable = 0;
226	            } catch (Exception ignored) {
227	                seatsAvailable = 0;
228	            }
229	
230	            // ---- Virtual Class ----
231	            if ("Virtual Class".equals(m) && "Virtual Class".equals(offeringMod)) {
232	
233	                // data.push({ columns: [
234	                //  {value:[custom1,classNumber,sku]}, {value:language}, {value:startDate}, ...
235	                // ]})
236	                data.add(new TableRow(Arrays.asList(
237	                        new TableCell(Arrays.asList(nvl(o.custom1), nvl(o.classNumber), nvl(skuGlobalCode))),
238	                        new TableCell(nvl(o.language)),
239	                        new TableCell(nvl(o.startDate)),
240	                        new TableCell(nvl(o.endDate)),
241	                        new TableCell(nvl(o.sessionId)),
242	                        new TableCell(seatsAvailable),
243	                        new TableCell(Arrays.asList(
244	                                String.valueOf(o.price),
245	                                nvl(o.currency),
246	                                String.valueOf(o.trainingCredit)
247	                        ))
248	                )));
249	
250	                // ---- Classroom ----
251	            } else if ("Classroom".equals(m) && "Classroom".equals(offeringMod)) {
252	
253	                // data.push({ columns: [
254	                //  {value:[custom1,classNumber,sku]}, {value:facility}, {value:language}, ...
255	                // ]})
256	                data.add(new TableRow(Arrays.asList(
257	                        new TableCell(Arrays.asList(nvl(o.custom1), nvl(o.classNumber), nvl(skuGlobalCode))),
258	                        new TableCell(nvl(o.facility)),
259	                        new TableCell(nvl(o.language)),
260	                        new TableCell(nvl(o.startDate)),
261	                        new TableCell(nvl(o.endDate)),
262	                        new TableCell(nvl(o.sessionId)),
263	                        new TableCell(seatsAvailable),
264	                        new TableCell(Arrays.asList(
265	                                String.valueOf(o.price),
266	                                nvl(o.currency),
267	                                String.valueOf(o.trainingCredit)
268	                        ))
269	                )));
270	
271	                // ---- Other mods ----
272	            } else if (isOtherMod(m)) {
273	
274	                // data.push({ columns: [{ value: [language,classNumber,sku] }] })
275	                data.add(new TableRow(Arrays.asList(
276	                        new TableCell(Arrays.asList(nvl(o.language), nvl(o.classNumber), nvl(skuGlobalCode)))
277	                )));
278	            }
279	        }
280	
281	        return data;
282	    }
283	
284	    public String getScheduleTableDataJson() {
285	        return scheduleTableDataJson != null ? scheduleTableDataJson : "[]";
286	    }
287	
288	    private String resolveLocation() {
289	        // Keep aligned with your current cookie/header strategy if needed.
290	        // Your JS default is "United States".
291	        return "United States";
292	    }
293	
294	    private String resolveAudienceType(String location) {
295	        // Your JS fallback: "Customer, ExternalX, " + location
296	        return "Customer, ExternalX, " + location;
297	    }
298	
299	    private String getCookieValue(SlingHttpServletRequest request, String cookieName) {
300	        Cookie cookie = request.getCookie(cookieName);
301	        return cookie != null ? cookie.getValue() : "";
302	    }
