package com.dell.core.models;

import com.adobe.granite.xss.XSSAPI;
import com.dell.core.bean.CourseInfoResponse;
import com.dell.core.bean.CoursePayload;
import com.dell.core.bean.Offering;
import com.dell.core.services.CourseApiClient;
import com.dell.core.services.EndPointsService;
import com.dell.core.use.EdSvcUserInfo;
import com.dell.core.utils.CourseDescriptionFormatter;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.apache.commons.lang3.StringUtils;
import org.apache.sling.api.SlingHttpServletRequest;
import org.apache.sling.models.annotations.DefaultInjectionStrategy;
import org.apache.sling.models.annotations.Model;
import org.apache.sling.models.annotations.injectorspecific.OSGiService;
import org.apache.sling.models.annotations.injectorspecific.SlingObject;
import org.json.JSONObject;

import javax.annotation.PostConstruct;
import javax.inject.Inject;
import javax.servlet.http.Cookie;
import java.util.*;
import java.util.stream.Collectors;

@Model(
        adaptables = SlingHttpServletRequest.class,
        defaultInjectionStrategy = DefaultInjectionStrategy.OPTIONAL
)
public class CourseDetailsModel {

    private static final ObjectMapper MAPPER = new ObjectMapper();

    @Inject private SlingHttpServletRequest request;
    @Inject private XSSAPI xss;


    @OSGiService
    private CourseApiClient apiClient;

    private boolean success;
    private CourseInfoResponse apiResponse;
    private CoursePayload course;
    private String formattedDescriptionHtml;
    private String courseInfoJson;

    private String blueprintBeforeScheduleHtml;
    private String blueprintAfterScheduleHtml;
    private String outlineHtml;

    private String scheduleTableDataJson = "[]";
    private String resolvedModType = "";

    public String getUseLocation() {
        return useLocation;
    }

    private String useLocation = "";

    private boolean isOtherMod(String modType) {
        return "On Demand Class".equals(modType)
                || "On Demand Lab".equals(modType)
                || "Exam Voucher".equals(modType)
                || "Training Credits".equals(modType)
                || "Subscription".equals(modType)
                || "Assessment".equals(modType);
    }

    private String resolvedCourseId = "";



    @OSGiService
    private EndPointsService endPointsService;

    private static class ParsedParams {
        String courseId;
        String mod;
    }

    private ParsedParams parseCourseAndMod() {
        ParsedParams p = new ParsedParams();

        String courseIdRaw = request.getParameter("courseID");
        String modRaw = request.getParameter("mod");

        // Normal path
        if (StringUtils.isNotBlank(courseIdRaw) && StringUtils.isNotBlank(modRaw)) {
            p.courseId = courseIdRaw.trim();
            p.mod = modRaw.trim();
            return p;
        }

        // Broken URL path: courseID contains "&mod=..."
        if (StringUtils.isNotBlank(courseIdRaw) && courseIdRaw.contains("&mod=")) {
            String[] parts = courseIdRaw.split("&mod=", 2);
            p.courseId = parts[0].trim();
            p.mod = (parts.length > 1) ? parts[1].trim() : "";
            return p;
        }

        // Another broken variant: "ESCPXS06248?mod=Classroom" (rare but happens)
        if (StringUtils.isNotBlank(courseIdRaw) && courseIdRaw.contains("?mod=")) {
            String[] parts = courseIdRaw.split("\\?mod=", 2);
            p.courseId = parts[0].trim();
            p.mod = (parts.length > 1) ? parts[1].trim() : "";
            return p;
        }

        // Fallback
        p.courseId = StringUtils.defaultString(courseIdRaw).trim();
        p.mod = StringUtils.defaultString(modRaw).trim();
        return p;
    }

    @PostConstruct
    protected void init() {
        try {
            ParsedParams parsed = parseCourseAndMod();
            String courseId = parsed.courseId;
            String modType  = parsed.mod;

            resolvedCourseId = courseId;
            resolvedModType = modType;


            if (StringUtils.isBlank(courseId) || StringUtils.isBlank(modType)) {
                fail();
                return;
            }

			EdSvcUserInfo userInfo = request.adaptTo(EdSvcUserInfo.class);

                String loc = userInfo != null ? StringUtils.defaultString(userInfo.getLocation()) : getCookieValue(request,"location","United States");
                String location = StringUtils.isBlank(loc) ? getCookieValue(request,"location","United States") : loc;


            String audType = userInfo != null ? StringUtils.defaultString(userInfo.getTWX_AudienceType()) : "";
            String audienceType = StringUtils.isBlank(audType) ? "Customer, ExternalX, " + location : audType;

            useLocation = location;
            // Build same JSON body as your frontend used
            JSONObject payload = new JSONObject();
            payload.put("audienceType", audienceType);
            payload.put("location", location);
            payload.put("country", location);
            payload.put("courseId", courseId);
            payload.put("deliveryType", modType);

            if (endPointsService == null) {
                throw new IllegalStateException("EndPointsService not injected into CourseDetailsModel");
            }

            String absoluteUrl = endPointsService.getStoreApiEndpoint() + "/CashMicroServices/catalog/getOfferingsAndCourseInfo";

            apiResponse = apiClient.getOfferingsAndCourseInfo(absoluteUrl, payload);

            if (apiResponse == null
                    || !"Success".equalsIgnoreCase(apiResponse.message)
                    || apiResponse.payload == null
                    || apiResponse.payload.isEmpty()) {
                fail();
                return;
            }

            course = apiResponse.payload.get(0);
            CourseDescriptionFormatter.SplitTabsHtml split =
                    CourseDescriptionFormatter.toSplitTabsHtml(course.courseDescription, xss);

            blueprintBeforeScheduleHtml = split.tab1BeforeScheduleHtml;
            blueprintAfterScheduleHtml  = split.tab1AfterScheduleHtml;
            outlineHtml                 = split.tab2OutlineHtml;

            resolvedModType = modType; // from parsed params earlier
            List<TableRow> rows = buildScheduleTableData(course.offeringsList, resolvedModType, nvl(course.skuModelCode));
            scheduleTableDataJson = MAPPER.writeValueAsString(rows);

            // Embed full response for JS-only validations/enhancements (NO network)
            String json = MAPPER.writeValueAsString(apiResponse);
            courseInfoJson = CourseApiClient.safeJsonForScriptTag(json);

            success = true;

        } catch (Exception e) {
            fail();
        }
    }

    private void fail() {
        success = false;
        apiResponse = null;
        course = null;
        formattedDescriptionHtml = "";
        courseInfoJson = "{}";
        blueprintBeforeScheduleHtml = "";
        blueprintAfterScheduleHtml = "";
        outlineHtml = "";
        resolvedModType = "";
        scheduleTableDataJson = "[]";
        resolvedCourseId = "";

    }

    private List<TableRow> buildScheduleTableData(List<Offering> offerings, String modType, String skuGlobalCode) {
        List<TableRow> data = new ArrayList<>();

        if (offerings == null || offerings.isEmpty()) {
            return data;
        }

        // Normalize to avoid NPE/spacing issues
        String m = StringUtils.defaultString(modType).trim();

        for (Offering o : offerings) {
            if (o == null) continue;

            String offeringMod = StringUtils.defaultString(o.modalityName).trim();

            // seatsAvailable = round(maxCT - studCT) (same as your JS math)
            int seatsAvailable = 0;
            try {
                int max = (o.maxCT != null) ? o.maxCT : 0;
                int used = (o.studCT != null) ? o.studCT : 0;
                seatsAvailable = Math.round(max - used);
                if (seatsAvailable < 0) seatsAvailable = 0;
            } catch (Exception ignored) {
                seatsAvailable = 0;
            }

            // ---- Virtual Class ----
            if ("Virtual Class".equals(m) && "Virtual Class".equals(offeringMod)) {

                // data.push({ columns: [
                //  {value:[custom1,classNumber,sku]}, {value:language}, {value:startDate}, ...
                // ]})
                data.add(new TableRow(Arrays.asList(
                        new TableCell(Arrays.asList(nvl(o.custom1), nvl(o.classNumber), nvl(skuGlobalCode))),
                        new TableCell(nvl(o.language)),
                        new TableCell(nvl(o.startDate)),
                        new TableCell(nvl(o.endDate)),
                        new TableCell(nvl(o.sessionId)),
                        new TableCell(seatsAvailable),
                        new TableCell(Arrays.asList(
                                String.valueOf(o.price),
                                nvl(o.currency),
                                String.valueOf(o.trainingCredit)
                        ))
                )));

                // ---- Classroom ----
            } else if ("Classroom".equals(m) && "Classroom".equals(offeringMod)) {

                // data.push({ columns: [
                //  {value:[custom1,classNumber,sku]}, {value:facility}, {value:language}, ...
                // ]})
                data.add(new TableRow(Arrays.asList(
                        new TableCell(Arrays.asList(nvl(o.custom1), nvl(o.classNumber), nvl(skuGlobalCode))),
                        new TableCell(nvl(o.facility)),
                        new TableCell(nvl(o.language)),
                        new TableCell(nvl(o.startDate)),
                        new TableCell(nvl(o.endDate)),
                        new TableCell(nvl(o.sessionId)),
                        new TableCell(seatsAvailable),
                        new TableCell(Arrays.asList(
                                String.valueOf(o.price),
                                nvl(o.currency),
                                String.valueOf(o.trainingCredit)
                        ))
                )));

                // ---- Other mods ----
            } else if (isOtherMod(m)) {

                // data.push({ columns: [{ value: [language,classNumber,sku] }] })
                data.add(new TableRow(Arrays.asList(
                        new TableCell(Arrays.asList(nvl(o.language), nvl(o.classNumber), nvl(skuGlobalCode)))
                )));
            }
        }

        return data;
    }

    public String getScheduleTableDataJson() {
        return scheduleTableDataJson != null ? scheduleTableDataJson : "[]";
    }

    private String resolveLocation() {
        // Keep aligned with your current cookie/header strategy if needed.
        // Your JS default is "United States".
        return "United States";
    }

    private String resolveAudienceType(String location) {
        // Your JS fallback: "Customer, ExternalX, " + location
        return "Customer, ExternalX, " + location;
    }

    private String getCookieValue(SlingHttpServletRequest request, String cookieName) {
        Cookie cookie = request.getCookie(cookieName);
        return cookie != null ? cookie.getValue() : "";
    }

    private String getCookieValue(SlingHttpServletRequest request, String cookieName, String defaultValue) {
        Cookie cookie = request.getCookie(cookieName);
        return cookie != null ? cookie.getValue() : defaultValue;
    }

    // ------- HTL getters -------
    public boolean isSuccess() { return success; }

    public String getCourseTitle() { return course != null ? nvl(course.title) : ""; }
    public String getModType() {
        // Always prefer the parsed + resolved value
        if (StringUtils.isNotBlank(resolvedModType)) {
            return resolvedModType;
        }

        // Fallback only
        return StringUtils.defaultString(request.getParameter("mod")).trim();
    }
    public String getCourseId() {
        if (StringUtils.isNotBlank(resolvedCourseId)) {
            return resolvedCourseId;
        }
        return StringUtils.defaultString(request.getParameter("courseID")).trim();
    }

    public String getBlueprintBeforeScheduleHtml() {
        return blueprintBeforeScheduleHtml != null ? blueprintBeforeScheduleHtml : "";
    }

    public String getBlueprintAfterScheduleHtml() {
        return blueprintAfterScheduleHtml != null ? blueprintAfterScheduleHtml : "";
    }

    public String getOutlineHtml() {
        if (outlineHtml == null) {
            return "";
        }
        // remove whitespace-only content
        String trimmed = outlineHtml.replaceAll("<[^>]*>", "").trim();
        return trimmed.isEmpty() ? "" : outlineHtml;
    }

    public String getDuration() {
        String d = course != null ? course.duration : null;
        return StringUtils.isBlank(d) ? "N/A" : d;
    }

    public double getPrice() { return course != null ? course.price : 0; }
    public double getTrainingCredit() { return course != null ? course.trainingCredit : 0; }
    public String getCurrency() { return course != null ? nvl(course.currency) : ""; }

    public String getSkuModelCode() { return course != null ? nvl(course.skuModelCode) : ""; }

    public String getFormattedDescriptionHtml() {
        return formattedDescriptionHtml != null ? formattedDescriptionHtml : "";
    }

    public List<OfferingView> getOfferings() {
        if (course == null || course.offeringsList == null) return Collections.emptyList();
        return course.offeringsList.stream().map(OfferingView::new).collect(Collectors.toList());
    }

    public String getCourseInfoJson() {
        return courseInfoJson != null ? courseInfoJson : "{}";
    }

    private String nvl(String s) { return s == null ? "" : s; }

    public static final class TableCell {
        private final Object value;

        public TableCell(Object value) {
            this.value = value;
        }

        public Object getValue() {
            return value;
        }
    }

    public static final class TableRow {
        private final List<TableCell> columns;

        public TableRow(List<TableCell> columns) {
            this.columns = columns;
        }

        public List<TableCell> getColumns() {
            return columns;
        }
    }

}

