	String pageLL;
	String country;

	@PostConstruct
	public void init() {
		try {
			Set<String> runmode = GenericUtil.getRunModes();
			LOG.info("SiteMap Scheduler is running " + runmode);

			ssoEndpoint = endPointsService.getSsoEndpoint();
			String getUserInfoUrl = endPointsService.getSamlGetUserInfoEndpoint();

			LOG.info("SSO Endpoint " + ssoEndpoint);

			final HttpServletResponse httpResponse = response;
			deleteCookie(request, response, "s_sq");
			String userInfo = "";
			//DefaultHttpClient httpClient = null;
			HttpResponse responseREST = null;
			int responseCode = 0;
			StringBuffer result = new StringBuffer();
			String output;
			BufferedReader br = null;
			JSONObject jsonObj = new JSONObject();
			String pageURL = request.getRequestURL().toString();
			// Get the query parameters
			String queryString = request.getQueryString();

			// Check if the query string is null or empty
			String finalQString = (queryString == null || queryString.isEmpty()) ? "" : queryString;
			currUrl = pageURL + "?" + finalQString;
			LOG.info("page url : " + currUrl);
			ssoLink = ssoEndpoint + currUrl;
			LOG.info("sso redirect link : " + ssoLink);
			GetLocale getLocale = new GetLocale();
			Page currentPage = resource.adaptTo(Page.class);

			if(currentPage != null) {
				Locale pageLocale = currentPage.getLanguage(true);
				country = pageLocale.getCountry().toLowerCase();
				pageLL = pageLocale.getLanguage();
			} else {
				country = "us";
				pageLL = "en";
			}

			sessionId = request.getCookie("userKey") != null ? request.getCookie("userKey").getValue() : null;
			String nashId = request.getCookie("_nash") != null ? request.getCookie("_nash").getValue() : null;
			sessionId = sanitizeCookieValue(sessionId);
			audType = request.getCookie("AudienceTypes") != null ? request.getCookie("AudienceTypes").getValue() : "Guest";
			audType = sanitizeCookieValue(audType);
			LOG.info("audience type is " + audType);
			LOG.info("session ID / userkey is " + sessionId);
			Map<String, String> headers = new HashMap<>();
			headers.put("Authorization", "Bearer asdada");

			final boolean isBpaHome = StringUtils.containsIgnoreCase(currUrl, "bpa_homepage");
			LOG.info("isBpaHome : " + isBpaHome);
			final boolean isInternalPath = StringUtils.containsIgnoreCase(currUrl, "/internal/");
			LOG.info("isInternalPath : " + isInternalPath);
			final boolean isPublish = runmode != null && runmode.contains(GlobalConstants.PUBLISH);
			final String aud = StringUtils.upperCase(StringUtils.defaultString(audType));

			LOG.info("aud : " + aud);
			final boolean isGuest = "GUEST".equalsIgnoreCase(aud);
			final boolean isInternal = "INTERNAL".equalsIgnoreCase(aud);

			LOG.info("isGuest : " + isGuest);
			LOG.info("isInternal : " + isInternal);

			// GUEST + bpa_homepage => redirect to SSO
			if (isGuest && isBpaHome) {
				LOG.info("isGuest && isBpaHome");
				audienceType = audType;
				if (isPublish) {
					response.sendRedirect(ssoLink);
					return;
				}
			}

			// INTERNAL + bpa_homepage => redirect unauthorized
			if (isInternal && isBpaHome) {
				audienceType = audType;
				LOG.info("isInternal && isBpaHome");
				String cookieVal = request.getCookie("Username") != null
						? request.getCookie("Username").getValue()
						: "LOGGED USER";
				userName = sanitizeCookieValue(cookieVal);

				if (isPublish) {
					response.sendRedirect("/content/dell/en-us/unauthorized.html");
					return;
				}
			}

			// GUEST + /internal/ => redirect to SSO
			if (isGuest && isInternalPath) {
				LOG.info("isGuest && isInternalPath");
				audienceType = audType;
				if (isPublish) {
					response.sendRedirect(ssoLink);
					return;
				}
			}

			// Not INTERNAL/GUEST AND sessionId+audType present => do the API call
			if (StringUtils.isNotBlank(sessionId)
					&& StringUtils.isNotBlank(audType)
					&& !isGuest) {
				String serverName = parseSAMLService.getServiceHost();
				LOG.info("full url : " + getUserInfoUrl +sessionId.replace("\"", ""));
				try (CloseableHttpClient httpClient = HttpClients.createDefault()) {
//					userInfo = genericRESTCallService.callRESTService(serverName + "/elearning/authSvc/redisCache/getUserInfo/" + sessionId.replace("\"", ""), null, "GET", headers);
					//httpClient = new DefaultHttpClient();
					String url = getUserInfoUrl +sessionId.replace("\"", "");
					LOG.info("the SC Auth URL is " + url);
					HttpGet getRequest = new HttpGet(url);
					getRequest.addHeader("Cookie", "_nash=" + nashId);
					getRequest.addHeader("Cookie", "AudienceTypes=" + audType);
					responseREST = httpClient.execute(getRequest);
					responseCode = responseREST.getStatusLine().getStatusCode();
					LOG.info("responseCode for getUserinfo: " + responseCode);
					br = new BufferedReader(new InputStreamReader((responseREST.getEntity().getContent())));
					result = new StringBuffer();
					output = "";
					while ((output = br.readLine()) != null) {
						result.append(output);
					}
					br.close();
					//httpClient.getConnectionManager().shutdown();
					userInfo = result.toString();
				} catch (Exception e){
					LOG.error("Exception during rest call : " + e.getMessage());
				}
				LOG.info("userInfo : " + userInfo);
				if(userInfo != null) {
					JSONObject userSessionObj = new JSONObject(userInfo);
					JSONArray jsonUserArray = new JSONArray();
					userInfo = jsonUserArray.put(userSessionObj).toString();
					JSONArray userJsonArray = new JSONArray(userInfo);
					JSONObject userJsonObj = userJsonArray.getJSONObject(0);
					if(userJsonObj.optBoolean("success")) {
						userName = userJsonObj.optString("learnerName") != null ? userJsonObj.optString("learnerName") : "";
						audienceType = userJsonObj.optString("audienceType") != null ? userJsonObj.optString("AudienceTypes") : "";
						location = userJsonObj.optString("location") != null ? userJsonObj.optString("location") : "";
						LLDisplay = userJsonObj.optString("LL_display") != null ? userJsonObj.optString("LL_display") : "";
						personType = userJsonObj.optString("person_type") != null ? userJsonObj.optString("person_type") : "";
						balance = userJsonObj.optString("balance") != null ? userJsonObj.optString("balance") : "0";
						authId = userJsonObj.optString("authid") != null ? userJsonObj.optString("authid") : "";
						sessionFlag = "valid";
						TWX_AudienceType = userJsonObj.optString("TWX_AudienceType") != null ? userJsonObj.optString("TWX_AudienceType") : "";
						email_id = userJsonObj.optString("email_id") != null ? userJsonObj.optString("email_id") : "";
						orgNo = userJsonObj.optString("orgNo") != null ? userJsonObj.optString("orgNo") : "";
						empid = userJsonObj.optString("empid") != null ? userJsonObj.optString("empid") : "";
						categories = userJsonObj.optString("categories") != null ? userJsonObj.optString("categories") : "";
						orgName = userJsonObj.optString("company_name") != null ? userJsonObj.optString("company_name") : "";
					} else{
						deleteAllCookie(request, response);
						createCookie(request, response, "Guest", "AudienceTypes", -1);
						createCookie(request, response, "United States", "location", -1);
						sessionFlag = "invalid";
						return;
					}
				}
				if(!Objects.equals(audienceType, "Partner")){
					if(currUrl.contains("bpa_homepage")) {
						response.sendRedirect("/content/dell/" +  pageLL + "-" + country + "/unauthorized.html");
					}
				}
			}else if(StringUtils.equalsIgnoreCase(audType, "GUEST")) {
				audienceType = audType;
			}

		}catch (Exception e) {
			LOG.error("Error in Use Class EdSVc User Info: "+e.getMessage());
			e.printStackTrace();
		}
