			}

			String sanitizedValue = null;
			if (pCookieValue != null) {
				sanitizedValue = StringUtils.strip(pCookieValue, "\"");
				if (!isSafeCookieValue(sanitizedValue)) {
					LOG.warn("Unsafe cookie value detected for: " + pCookieName);
					return;
				}
			}

			String domainName = getDomainName(pHttpRequest);
			LOG.info("domainName:" + domainName);

			if (domainName == null || domainName.isEmpty()) {
				domainName = "localhost";
			} else if (!isValidDomain(domainName)) {
				LOG.warn("Invalid domain detected: " + domainName);
				return;
			}

			Cookie cookie = new Cookie(pCookieName, sanitizedValue);
			cookie.setDomain(domainName);
			cookie.setPath("/");
			cookie.setMaxAge(maxAge);

			pHttpResponse.addCookie(cookie);
			LOG.info("Cookie created: " + pCookieName);
		} catch (Exception e) {
			LOG.error("Exception in createCookie: " + e.getMessage(), e);
		}
	}

	public static void deleteCookie(HttpServletRequest request, HttpServletResponse response, String cookieName) {
		try {
			LOG.info("Delete cookie triggered for: " + cookieName);

			if (!isValidCookieName(cookieName)) {
				LOG.warn("Invalid cookie name for deletion: " + cookieName);
				return;
			}

			String domainName;
			try {
				domainName = getDomainName(request);
				if (domainName == null || domainName.isEmpty()) {
					domainName = "localhost";
				} else if (!isValidDomain(domainName)) {
					LOG.warn("Invalid domain for cookie deletion: " + domainName);
					return;
				}
			} catch (MalformedURLException e) {
				LOG.warn("Could not determine domain for cookie deletion", e);
				domainName = "localhost";
			}

			Cookie cookie = new Cookie(cookieName, null);
			cookie.setMaxAge(0);
			cookie.setPath("/");
			cookie.setDomain(domainName);

			response.addCookie(cookie);
			LOG.info("Cookie deleted: " + cookieName);
		} catch (Exception e) {
			LOG.error("Exception in deleteCookie: " + e.getMessage(), e);
		}
	}

	private void deleteAllCookie(HttpServletRequest pHttpRequest, HttpServletResponse pHttpResponse) {
		try {
			// First, get all cookie names from the request
			List<String> validCookieNames = new ArrayList<>();
			Cookie[] requestCookies = pHttpRequest.getCookies();

			if (requestCookies != null) {
				for (Cookie cookie : requestCookies) {
					if (cookie != null && cookie.getName() != null) {
						String name = cookie.getName();
						// Only collect valid cookie names
						if (name.matches("^[a-zA-Z0-9!#$%&'*+.^_`|~-]+$")) {
							validCookieNames.add(name);
						} else {
							LOG.warn("Ignoring cookie with invalid name in request");
						}
					}
				}
			}

			// Extract safe domain
			String safeDomain = null;
			try {
				String serverName = pHttpRequest.getServerName();
				if (serverName != null && !serverName.isEmpty()) {
					if (serverName.contains(".")) {
						String[] parts = serverName.split("\\.");
						if (parts.length > 1) {
							StringBuilder sb = new StringBuilder();
							safeDomain = sb.append(parts[parts.length - 2])
									.append(".")
									.append(parts[parts.length - 1])
									.toString();
						} else {
							safeDomain = serverName;
						}
					} else {
						safeDomain = serverName;
					}

					// Validate domain
					if (!safeDomain.matches("^[a-zA-Z0-9.-]+$") || safeDomain.contains("..")) {
						LOG.warn("Invalid domain: " + safeDomain);
						safeDomain = "localhost";
					}
				} else {
					safeDomain = "localhost";
				}
			} catch (Exception e) {
				LOG.warn("Error determining domain, using localhost", e);
				safeDomain = "localhost";
			}

			// Now delete all valid cookies with a safe domain
			for (String cookieName : validCookieNames) {
				try {
					// Create a completely new cookie with controlled parameters
					Cookie deleteCookie = new Cookie(cookieName, null);
					deleteCookie.setMaxAge(0);
					deleteCookie.setPath("/");
					deleteCookie.setDomain(safeDomain);

					pHttpResponse.addCookie(deleteCookie);
					LOG.info("Deleted cookie: " + cookieName);
				} catch (Exception e) {
					LOG.warn("Failed to delete cookie: " + cookieName, e);
				}
			}
		} catch (Exception e) {
			LOG.error("Exception in deleteAllCookie", e);
		}
	}

	private static boolean isValidCookieName(String cookieName) {
		return cookieName != null &&
				!cookieName.isEmpty() &&
				cookieName.length() <= 256 &&
				Pattern.matches("^[a-zA-Z0-9!#$%&'*+.^_`|~-]+$", cookieName);
	}

	private static boolean isValidDomain(String domain) {
		return domain != null &&
				!domain.isEmpty() &&
				domain.length() <= 253 &&
				Pattern.matches("^[a-zA-Z0-9.-]+$", domain) &&
				!domain.contains("..");
	}

	private static boolean isSafeCookieValue(String value) {
		return value == null ||
				(!value.contains("\r") &&
						!value.contains("\n") &&
						Pattern.matches("^[a-zA-Z0-9_\\-\\.@,;:+*=\\s]*$", value));
	}

	private static String getDomainName(HttpServletRequest pHttpRequest) throws MalformedURLException {
		URL url = new URL(pHttpRequest.getRequestURL().toString());
		String domainName = "";
		String hostName = url.getHost();
		LOG.info("hostname:" + hostName);

		if (hostName != null) {
			if (hostName.contains(".")) {
				String[] hostNameStrArr = hostName.split("\\.");
				int length = hostNameStrArr.length;
				if (length > 1) {
					StringBuilder sb = new StringBuilder();
					domainName = sb.append(hostNameStrArr[length - 2])
							.append(".")
							.append(hostNameStrArr[length - 1]).toString();
				}
			} else if (hostName.contains(":")) {
				String[] hostNameStrArr = hostName.split("\\:");
				int length = hostNameStrArr.length;
				if (length > 0) {
					domainName = hostNameStrArr[0];
				}
			} else {
				domainName = hostName;
			}
		}

		return domainName;
	}

}

