package com.dell.core.connection.api.common;

import com.dell.core.connection.api.EMCRESTCall;
import org.apache.commons.lang3.StringUtils;
import org.apache.http.Header;
import org.apache.http.HttpEntity;
import org.apache.http.NameValuePair;
import org.apache.http.message.BasicHeader;
import org.apache.http.message.BasicNameValuePair;

import java.util.ArrayList;

public abstract class AbstractEMCRESTCall implements EMCRESTCall {
	private String path;
	private final String method;
	private boolean hasDefaultHeaders = true;

	private final ArrayList<NameValuePair> parameters = new ArrayList<NameValuePair>();
	private final ArrayList<Header> headers = new ArrayList<Header>();

	public AbstractEMCRESTCall() {
		this.method = EMCRESTCall.METHOD_GET;
	}

	public AbstractEMCRESTCall(final String method) {
		this.method = method;
	}

	public String getMethod() {
		return method;
	}

	public String getPath() {
		return path;
	}

	public void setPath(final String path) {
		this.path = path;
	}

	public ArrayList<NameValuePair> getQueryParameters() {
		return parameters;
	}

	public void addParameter(final String key, final String value) {
		if (StringUtils.isBlank(key)) {
			throw new IllegalArgumentException("key may not be blank");
		}

		if (StringUtils.isNotBlank(value)) {
			parameters.add(new BasicNameValuePair(key, value));
		}
	}

	public ArrayList<Header> getHeaders() {
		return headers;
	}

	public void addHeader(final String key, final String value) {
		if (StringUtils.isBlank(key)) {
			throw new IllegalArgumentException("key may not be blank");
		}

		if (StringUtils.isNotBlank(value)) {
			headers.add(new BasicHeader(key, value));
		}
	}

	public String getContentType() {
		return CONTENT_TYPE_JSON;
	}

	public HttpEntity getEntity() {
		return null;
	}

	public boolean hasDefaultHeaders() {
        return hasDefaultHeaders;
    }
    public void setHasDefaultHeaders(boolean hasDefaultHeaders) {
        this.hasDefaultHeaders = hasDefaultHeaders;
    }

	@Override
	public String toString() {
		return "Command: " + getMethod() + " " + getPath() + "?" + getQueryParameters().toString();
	}


}

