                console.log("[Preferences] EducationPortalPreferences success, calling Redis update");
                callRedisUpdate(categories);
            },
            error: function (xhr) {
                console.error("[Preferences] EducationPortalPreferences failed:", xhr.status, xhr.responseText);
                location.reload();
            },
            complete: function () {
                hideLoader();
            }
        });
    }

