            console.warn("[Preferences] no userKey, reloading anyway");
            location.reload();
            return;
        }

        showLoader();

        const payload = {
            categories: categories.join(",")
        };

        $jq.ajax({
            url: "/eduservice/cash.json/redisCache/updateUserPref/" + userKey,
            type: "POST",
            data: JSON.stringify(payload),
            contentType: "application/json",
            dataType: "json",
            success: function () {
                console.log("[Preferences] Redis update success, reloading page");
            },
            error: function (xhr) {
                console.error("[Preferences] Redis update failed:", xhr.status, xhr.responseText);
            },
            complete: function () {
                hideLoader();
                console.log("[Preferences] reloading now");
                location.reload();
            }
        });
    }

    function getCookie(name) {
        const match = document.cookie.match(
            new RegExp("(^| )" + name + "=([^;]+)")
        );
        return match ? match[2] : "";
    }

});

