$jq(document).ready(function () {

    var $headerElement = $jq(".dt-emc-header");
    var $categoryWrapper = $jq("#preferences-container");

    if (!$categoryWrapper.length || !$headerElement.length) {
        return;
    }

    const defaultCategories = [
        "Big Data",
        "Cloud",
        "Converged Infrastructure",
        "Data Protection",
        "Desktop",
        "Networking",
        "Security",
        "Servers",
        "Storage",
        "Systems Management"
    ];

    const email = $headerElement[0].dataset.eid || "";
    const language = $headerElement[0].dataset.language || "English";
    const country = $headerElement[0].dataset.location || "";

    const headerCategoriesRaw = $headerElement[0].dataset.category;

    let headerCategories = [];
    if (headerCategoriesRaw) {
        headerCategories = headerCategoriesRaw.split(",").map(c => c.trim());
    }

    let selectedCategories = [];

    if (headerCategories.length) {
        selectedCategories = headerCategories;
        localStorage.setItem("selectedCategories", JSON.stringify(selectedCategories));
    } else {
        try {
            const stored = localStorage.getItem("selectedCategories");
            if (stored) selectedCategories = JSON.parse(stored);
        } catch (e) {}
    }

    renderCategories(defaultCategories, selectedCategories);

    $categoryWrapper.on("click", ".dds__tag", function () {
        handleCategorySelection($jq(this));
    });

    function renderCategories(categories, selected) {

        let html = "";

        categories.forEach(function (category) {
            const isSelected = selected.indexOf(category) > -1;

            html += `
                <div class="dds__tag dds__preftag dds__mb-2 dds__tag--md ${isSelected ? "selected" : "unselected"}"
                     data-category="${category}">
                    <button type="button" class="dds__preferencebtn">
                        ${category}
                    </button>
                </div>
            `;
        });

        $categoryWrapper.html(html);

        $categoryWrapper.find(".dds__tag").each(function () {
            if (window.DDS && DDS.Tag) {
                DDS.Tag(this);
            }
        });
    }

    function handleCategorySelection($tag) {

        $tag.toggleClass("selected unselected");

        selectedCategories = $categoryWrapper
            .find(".dds__preftag.selected")
            .map(function () {
                return $jq(this).data("category");
            })
            .get();

        localStorage.setItem("selectedCategories", JSON.stringify(selectedCategories));

        callEducationPortalPreferences(selectedCategories);
    }

    let pendingCalls = 0;

    function showLoader() {
        pendingCalls++;
        $jq(".dds__srch-data-loading").removeClass("dds__d-none");
        $jq(".dds__srch-data-container").addClass("dds__d-none");
        $jq(".dds__api-error").addClass("dds__d-none");
    }

    function hideLoader() {
        pendingCalls--;
        if (pendingCalls <= 0) {
            pendingCalls = 0;
            $jq(".dds__srch-data-loading").addClass("dds__d-none");
            $jq(".dds__srch-data-container").removeClass("dds__d-none");
        }
    }

    function callEducationPortalPreferences(categories) {

        showLoader();

        const payload = {
            preferences: {
                modalities: [],
                categories: categories,
                email: email,
                location: { country: country },
                language: language
            }
        };

        $jq.ajax({
            url: "/CashMicroServices/eduPortal/EducationPortalPreferences",
            type: "POST",
            data: JSON.stringify(payload),
            contentType: "application/json",
            dataType: "json",
            success: function () {
                callRedisUpdate(categories);
            },
            error: function () {
                location.reload();
            },
            complete: function () {
                hideLoader();
            }
        });
    }

    function callRedisUpdate(categories) {

        const userKey = getCookie("userKey");
        if (!userKey) {
            location.reload();
            return;
        }

        showLoader();

        const payload = {
            categories: categories.join(",")
        };

        $jq.ajax({
            url: "/eduservice/cash.json/redisCache/updateUserPref/" + userKey,
            type: "POST",
            data: JSON.stringify(payload),
            contentType: "application/json",
            dataType: "json",
            complete: function () {
                hideLoader();
                location.reload();
            }
        });
    }

    function getCookie(name) {
        const match = document.cookie.match(
            new RegExp("(^| )" + name + "=([^;]+)")
        );
        return match ? match[2] : "";
    }

});

